INSERT INTO blueprints (id, serial_key, type, name, description, flavor, category, rarity, tags, config, stats, metadata, rating_avg, activation_count)
VALUES ('fleet-01', 'SS-ZW5D-TEPE-5FPL-0CPG', 'spaceship', 'SaaS Startup', 'You orchestrate a full-stack startup crew — routing product decisions, engineering tasks, marketing campaigns, and support tickets to the right specialist. Ensure seamless handoffs between build and go-to-market.', 'Ship faster. Scale smarter.', 'Engineering', 'class-2', ARRAY['saas','startup','tech'], '{"workflows":[{"name":"Feature Ship Pipeline","nodes":[{"id":"n1","type":"agent","label":"Product Manager","config":{"prompt":"Break down this feature request into user stories with acceptance criteria and priority.","agentRole":"Ops"}},{"id":"n2","type":"agent","label":"CTO Agent","config":{"prompt":"Review the user stories and create a technical implementation plan with estimates.","agentRole":"Engineering"}},{"id":"n3","type":"agent","label":"Marketing Lead","config":{"prompt":"Draft a release announcement and changelog entry for this feature.","agentRole":"Content"}},{"id":"n4","type":"output","label":"Ship It","config":{"format":"text"}}],"connections":[{"to":"n2","from":"n1"},{"to":"n3","from":"n2"},{"to":"n4","from":"n3"}]},{"name":"Customer Feedback Loop","nodes":[{"id":"n1","type":"agent","label":"Support Agent","config":{"prompt":"Summarize recent customer feedback tickets, categorize by theme and sentiment.","agentRole":"Support"}},{"id":"n2","type":"agent","label":"Product Manager","config":{"prompt":"Prioritize the feedback themes into actionable items for the next sprint.","agentRole":"Ops"}},{"id":"n3","type":"output","label":"Backlog","config":{"format":"text"}}],"connections":[{"to":"n2","from":"n1"},{"to":"n3","from":"n2"}]}],"suggested_agents":["bp-agent-06","bp-agent-05","bp-agent-02","bp-agent-04"]}'::jsonb, '{"cost":"$149","crew":"4","tier":"PRO","slots":"4"}'::jsonb, '{"caps":["Route feature requests from product to engineering to launch","Coordinate cross-functional sprints across all departments","Auto-escalate blockers and sync standup summaries"],"tier":"pro","confi