alculate totals, and flag any issues.","agentRole":"Ops"}},{"id":"n2","type":"agent","label":"Customer Comms","config":{"prompt":"Draft an order confirmation email for the customer with estimated delivery date.","agentRole":"Support"}},{"id":"n3","type":"output","label":"Done","config":{"format":"text"}}],"connections":[{"to":"n2","from":"n1"},{"to":"n3","from":"n2"}]},{"name":"Weekly Sales Report","nodes":[{"id":"n1","type":"agent","label":"Data Analyst","config":{"prompt":"Analyze this week''s sales data. Calculate revenue, top products, and trends vs last week.","agentRole":"Analytics"}},{"id":"n2","type":"agent","label":"Content Writer","config":{"prompt":"Write a concise weekly sales summary newsletter from the analysis for the team.","agentRole":"Content"}},{"id":"n3","type":"output","label":"Report","config":{"format":"text"}}],"connections":[{"to":"n2","from":"n1"},{"to":"n3","from":"n2"}]}],"suggested_agents":["bp-agent-05","bp-agent-04","bp-agent-02","bp-agent-03"]},"card_num":"NS-F02","recommended_class":"class-1"}'::jsonb, 0, 0)
